1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	// Base premiums for main (non-component) items. Components such as runes are
14	// priced separately via componentBasePremium and never read from this table.
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	const FIRST_INSURANCE_MULTIPLIER = 1.1;
22	
23	const COMPONENT_TYPES = ["rune", "moonstone"];
24	const COMPONENT_BASE_PREMIUM = 25;
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_BLOCK_PREMIUM = 60;
27	
28	const isComponent = (item: Item): boolean =>
29	  COMPONENT_TYPES.includes(item.type);
30	
31	// Base premium for `count` alike components: a block premium applies only for
32	// exactly one block's worth (3) of components; otherwise each is priced individually.
33	const componentBasePremium = (count: number): number => {
34	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
35	  return count * COMPONENT_BASE_PREMIUM;
36	};
37	
38	// Every item is treated as first insurance today, so the 10% surcharge is
39	// applied uniformly to each base premium.
40	const withFirstInsurance = (basePremium: number): number =>
41	  basePremium * FIRST_INSURANCE_MULTIPLIER;
42	
43	// Round up in MHPCO's favour, guarding against floating-point noise
44	// (e.g. 197.50000000001 should still round to 198, not 199).
45	const roundUpInMHPCOFavor = (amount: number): number =>
46	  Math.ceil(Number(amount.toFixed(6)));
47	
48	export const quote = (
49	  items: Item[],
50	  customer: Customer,
51	  contractIndex: number,
52	): number => {
53	  const mainItems = items.filter((item) => !isComponent(item));
54	  const componentItems = items.filter((item) => isComponent(item));
55	
56	  const mainBase = mainItems.reduce(
57	    (sum, item) => sum + withFirstInsurance(BASE_PREMIUMS[item.type]),
58	    0,
59	  );
60	
61	  // The block rule is per-type ("alike" = same type), so group components by
62	  // type and price each type's count independently before summing.
63	  const countsByComponentType = new Map<string, number>();
64	  for (const item of componentItems) {
65	    countsByComponentType.set(
66	      item.type,
67	      (countsByComponentType.get(item.type) ?? 0) + 1,
68	    );
69	  }
70	  let componentBase = 0;
71	  for (const count of countsByComponentType.values()) {
72	    componentBase += withFirstInsurance(componentBasePremium(count));
73	  }
74	
75	  return roundUpInMHPCOFavor(mainBase + componentBase + PROCESSING_FEE);
76	};
77	
78	export const claim = (): number => {
79	  return undefined as unknown as number;
80	};
